    # Prevent common injection patterns
    dangerous_patterns = ["__", "import", "exec", "eval", "lambda", "open", "file"]
    expr_lower = expr.lower()
    if any(pattern in expr_lower for pattern in dangerous_patterns):
        return ""

    try:
        import ast
        import operator

        # Parse to ensure it's a valid expression
        tree = ast.parse(expr, mode='eval')

        # Validate that the AST only contains allowed node types
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,  # For Python < 3.8 compatibility
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
        )

        def validate_node(node):
            if not isinstance(node, allowed_node_types):
                return False
            for child in ast.walk(node):
                if not isinstance(child, allowed_node_types):
                    return False
            return True

        if not validate_node(tree):
            return ""

        # Safe evaluation using ast.literal_eval for constants and manual traversal
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                # Python 3.8+
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Invalid constant type")
            elif isinstance(node, ast.Num):
                # Python < 3.8
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operator")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operator")
                return op(operand)
            else:
                raise ValueError("Unsupported node type")

        result = safe_eval(tree)

        # Validate result is a number
        if not isinstance(result, (int, float)):
            return ""

        # Handle float results
        if isinstance(result, float):
            if result.is_integer():
                return str(int(result))
            else:
                return str(result)

        return str(result)

